import React from "react";
import { motion, useAnimation } from "framer-motion";
import { useInView } from "react-intersection-observer";

const About = (props) => {
  const controls = useAnimation();
  const [ref, inView] = useInView({ threshold: 0.2 });

  React.useEffect(() => {
    if (inView) {
      controls.start("visible");
    } else {
      controls.start("hidden");
    }
  }, [inView, controls]);

  let sectionName, hello, about;
  if (props.resumeBasicInfo) {
    sectionName = props.resumeBasicInfo.section_name.about;
    hello = props.resumeBasicInfo.description_header;
    about = props.resumeBasicInfo.description;
  }

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.3 }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { opacity: 1, y: 0, transition: { duration: 0.6 } }
  };

  return (
    <section 
      id="about" 
      ref={ref} 
      style={{ 
        padding: "100px 0", 
        position: "relative", 
        overflow: "hidden", 
        background: "var(--about-background)",
        transition: "background 0.6s ease" 
      }}
    >
      <motion.div 
        animate={{ 
          scale: [1, 1.1, 1],
          rotate: [0, 90, 0]
        }}
        transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
        style={{
          position: "absolute",
          top: "-10%",
          right: "-5%",
          width: "500px",
          height: "500px",
          background: "radial-gradient(circle, rgba(174,148,79,0.15) 0%, rgba(186,170,128,0) 70%)",
          filter: "blur(60px)",
          zIndex: 0
        }}
      />

      <div className="container">
        <motion.div 
          className="row"
          initial="hidden"
          animate={controls}
          variants={containerVariants}
        >
          <div className="col-md-12" style={{ zIndex: 1 }}>
            <motion.h1 
              variants={itemVariants}
              style={{ 
                textAlign: "center", 
                marginBottom: "60px", 
                fontWeight: "700", 
                letterSpacing: "3px", 
                textTransform: "uppercase", 
                color: "var(--header-text)",
                transition: "color 0.6s ease"
              }}
            >
              {sectionName}
            </motion.h1>
          </div>

          <div className="col-md-4 mb-5 d-flex justify-content-center" style={{ zIndex: 1 }}>
            <motion.div 
              variants={itemVariants}
              style={{ position: "relative", width: "280px", height: "320px" }}
            >
              <img
                src={process.env.PUBLIC_URL + "/images/myProfile.jpg"}
                alt="Aditya Profile"
                style={{
                  width: "100%",
                  height: "100%",
                  objectFit: "cover",
                  borderRadius: "20px",
                  boxShadow: "0 20px 40px rgba(0,0,0,0.2)",
                  border: "5px solid var(--card-background)",
                  position: "relative",
                  zIndex: 2,
                  transition: "border-color 0.6s ease"
                }}
              />

              <div style={{
                position: "absolute",
                top: "-10px", 
                left: "-10px",
                width: "calc(100% + 20px)",
                height: "calc(100% + 20px)",
                border: "2px solid #AE944F",
                borderRadius: "25px", 
                zIndex: 1
              }} />
            </motion.div>
          </div>

          <div className="col-md-8" style={{ zIndex: 1 }}>
            <motion.div 
              variants={itemVariants}
              style={{
                background: "var(--card-background)",
                opacity: 0.95,
                backdropFilter: "blur(12px)",
                padding: "45px",
                borderRadius: "30px",
                border: "1px solid rgba(174,148,79, 0.2)",
                boxShadow: "0 15px 35px rgba(0,0,0,0.1)",
                transition: "background 0.6s ease"
              }}
            >
              <h2 style={{ marginBottom: "25px", fontWeight: "600", color: "#AE944F" }}>
  {hello} 
  <motion.div 
    animate={{ rotate: [0, 15, -15, 0] }} 
    transition={{ repeat: Infinity, duration: 2, repeatDelay: 1 }}
    style={{ display: "inline-block", marginLeft: "10px" }}
  >
    <span role="img" aria-label="waving hand">
      👋
    </span>
  </motion.div>
</h2>
              <p style={{ 
                fontSize: "1.6rem", 
                lineHeight: "1.8", 
                color: "var(--text-color)",
                textAlign: "justify",
                fontFamily: "'Segoe UI', Roboto, Helvetica, Arial, sans-serif",
                transition: "color 0.6s ease"
              }}>
                {about}
              </p>
            </motion.div>
          </div>
        </motion.div>
      </div>
    </section>
  );
};

export default About;
